solution:
public class Main {
    public static void main(String[] args) {
        int a = 5;
        int b = 5;
        int c = 8;
        if (a + b > c && a + c > b && b + c > a) {
            if (a == b && b == c) {
                System.out.println("Equilateral");
            } else if (a == b || a == c || b == c) {
                System.out.println("Isosceles");
            } else {
                System.out.println("Scalene");
            }
        } else {
            System.out.println("Not a valid triangle");
        }
    }
}

